try {
  const j0 = items[0].json;
  if (j0._error || j0.error) {
    return [
      {
        json: {
          _error: true,
          _errorMessage:
            (j0.error && j0.error.message) || j0.errorMessage || 'AI classification failed or returned empty',
          _errorNode: 'ClassifyMessage',
          _timestamp: new Date().toISOString(),
        },
      },
    ];
  }

  const item = $input.first();
  const rawText = item.json.message?.content
  || item.json.text
  || item.json.content
  || item.json.choices?.[0]?.message?.content
  || item.json.data?.choices?.[0]?.message?.content
  || '';

let parsed;
try {
  const cleaned = String(rawText)
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();
  parsed = JSON.parse(cleaned);
  parsed.classification_failed = false;
} catch (e) {
  parsed = {
    intent: 'other',
    urgency: 'medium',
    estimated_value: 0,
    risk_type: 'none',
    risk_score: 0.5,
    missing_fields: [],
    recommended_action: 'request_approval',
    confidence: 0.3,
    classification_failed: true,
    summary: 'Classification failed - manual review needed'
  };
}

const input = $('Build Classification Input').first().json;

return [
  {
    json: {
      ...parsed,
      estimated_value: Number(parsed.estimated_value) || 0,
      risk_score: Number(parsed.risk_score) || 0,
      confidence: Number(parsed.confidence) || 0,
      missing_fields: Array.isArray(parsed.missing_fields) ? parsed.missing_fields : [],
      conversation_id: input.conversation_id,
      customer_name: input.customer_name,
      customer_email: input.customer_email,
      approval_mode: input.approval_mode,
      lead_id: input.lead_id || '',
    },
  },
];
} catch (error) {
  return [
    {
      json: {
        _error: true,
        _errorMessage: error.message,
        _errorNode: 'ParseAIResponse',
        _timestamp: new Date().toISOString(),
      },
    },
  ];
}

try {
  const parsed = $('Parse AI Response').first().json;
  const current = $input.first().json;
  const responseBody = current.body || current;
  const row = Array.isArray(responseBody) ? responseBody[0] : responseBody;
  const leadId = parsed.lead_id || (row && row.id) || current.id || '';

  return [
    {
      json: {
        ...parsed,
        lead_id: leadId,
        lead_row: row || null,
      },
    },
  ];
} catch (error) {
  return [
    {
      json: {
        _error: true,
        _errorMessage: error.message,
        _errorNode: 'NormalizeLeadResult',
        _timestamp: new Date().toISOString(),
      },
    },
  ];
}

const item = $input.first().json;
const businessName = item.business_name || '';
const industry = item.industry || '';
const services = item.services || '[]';
const pricingRules = item.pricing_rules || '{}';
const message = item.message || '';

const systemPrompt = 'You are a revenue intelligence classifier for a founder-led service business. You analyze customer messages and extract structured data.

Business context:
Name: ' + businessName + '
Industry: ' + industry + '
Services: ' + services + '
Pricing: ' + pricingRules + '

Classify the incoming customer message and return ONLY a valid JSON object. No markdown. No explanation. No preamble.

JSON schema (return exactly this structure):
{
  "intent": "pricing_request | booking_request | proposal_followup | complaint | support | other",
  "urgency": "low | medium | high",
  "estimated_value": number,
  "risk_type": "lead_may_go_cold | churn_risk | none",
  "risk_score": number between 0 and 1,
  "missing_fields": ["field1", "field2"],
  "recommended_action": "draft_reply | request_approval | schedule_followup | escalate_to_founder",
  "confidence": number between 0 and 1,
  "summary": "one sentence summary of the customer message"
}

Rules:
- urgency = high if message contains a pricing request, booking request, or any frustrated or angry tone
- urgency = medium for follow-ups or general inquiries
- urgency = low for informational questions only
- estimated_value: estimate in LKR using pricing_rules context; return 0 if impossible to estimate
- risk_score >= 0.8 means the lead is very likely to go cold or churn
- confidence reflects how certain you are about intent detection';

const requestBody = {
  model: 'nvidia/nemotron-3-ultra-550b-a55b:free',
  reasoning: { enabled: false },
  response_format: { type: 'json_object' },
  temperature: 0.1,
  max_tokens: 500,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: 'Customer message: ' + message }
  ]
};

return [{ json: { ...item, requestBody } }];

